// --- RepairShopr Webhooks ---

  let migrationProgress = { status: 'idle', counts: { customers: 0, tickets: 0, sms: 0, comms: 0 }, error: null as string | null };

  app.get('/api/repairshopr/migrate/status', (req, res) => {
    res.json(migrationProgress);
  });

  app.post('/api/repairshopr/migrate', async (req, res) => {
    if (!db) return res.status(500).json({ error: 'Firestore not configured' });
    if (migrationProgress.status !== 'idle' && migrationProgress.status !== 'completed' && migrationProgress.status !== 'error') {
        return res.status(200).json({ status: 'migration_already_running', progress: migrationProgress });
    }

    res.status(200).json({ status: 'migration_started' });

    (async () => {
        console.log("[Migration] Starting RepairShopr data migration in parallel...");
        migrationProgress = { status: 'running', counts: { customers: 0, tickets: 0, sms: 0, comms: 0 }, error: null };
        try {
            const subdomain = process.env.REPAIRSHOPR_SUBDOMAIN;
            const apiKey = process.env.REPAIRSHOPR_API_KEY;
            if (!subdomain || !apiKey) {
                migrationProgress.status = 'error';
                migrationProgress.error = 'Missing config';
                return;
            }

            const migrateCustomers = async () => {
                migrationProgress.status = 'syncing_customers';
                let page = 1, hasMore = true, total = 0, consecutiveErrors = 0;
                console.log("[Migration] Starting customer migration...");
                while(hasMore && consecutiveErrors < 10 && page <= 20000) {
                   try {
                       const resp = await axios.get(`https://${subdomain}.repairshopr.com/api/v1/customers`, {
                          params: { page },
                          headers: { 'Authorization': `Bearer ${apiKey}` }
                       });
                       const customers = resp.data.customers || [];
                       const meta = resp.data.meta || {};
                       console.log(`[Migration] Customers page ${page}/${meta.total_pages || '?'} - Got ${customers.length} items. Total: ${total + customers.length}`);

                       if (customers.length === 0) {
                           hasMore = false;
                           break;
                       }

                       const batch = writeBatch(db);
                       for (const c of customers) {
                          const docRef = doc(db, 'crm_customers', String(c.id));
                          batch.set(docRef, { ...c, id: String(c.id), uid: 'system_migration' }, { merge: true });
                       }
                       await batch.commit();

                       total += customers.length;
                       migrationProgress.counts.customers = total;

                       if (meta.total_pages && page < meta.total_pages) {
                           page++;
                       } else if (customers.length >= 10) { // Keep going if we even got 10 items
                           page++;
                       } else {
                           hasMore = false;
                       }

                       consecutiveErrors = 0;
                       await new Promise(r => setTimeout(r, 400));
                   } catch (e: any) { 
                       console.error(`[Migration] Customers page ${page} error:`, e.response?.status || e.message);
                       consecutiveErrors++;
                       if (e.response?.status === 404) hasMore = false;
                       else await new Promise(r => setTimeout(r, 2000));
                   }
                }
                console.log(`[Migration] Finished customer migration. Total: ${total}`);
                return total;
            };

            const migrateContacts = async () => {
                migrationProgress.status = 'syncing_contacts';
                let page = 1, hasMore = true, total = 0, consecutiveErrors = 0;
                console.log("[Migration] Starting contact migration...");
                while(hasMore && consecutiveErrors < 10 && page <= 20000) {
                   try {
                       const resp = await axios.get(`https://${subdomain}.repairshopr.com/api/v1/contacts`, {
                          params: { page },
                          headers: { 'Authorization': `Bearer ${apiKey}` }
                       });
                       const contacts = resp.data.contacts || [];
                       const meta = resp.data.meta || {};
                       console.log(`[Migration] Contacts page ${page}/${meta.total_pages || '?'} - Got ${contacts.length} items. Total: ${total + contacts.length}`);

                       if (contacts.length === 0) {
                           hasMore = false;
                           break;
                       }

                       const batch = writeBatch(db);
                       for (const c of contacts) {
                          const contactId = `contact_${c.id}`;
                          const docRef = doc(db, 'crm_customers', contactId);
                          batch.set(docRef, { 
                              ...c, 
                              id: contactId, 
                              rs_contact_id: c.id,
                              rs_customer_id: c.customer_id,
                              firstname: c.name || c.firstname || '',
                              lastname: c.lastname || '',
                              uid: 'system_migration',
                              is_contact: true
                          }, { merge: true });
                       }
                       await batch.commit();

                       total += contacts.length;

                       if (meta.total_pages && page < meta.total_pages) {
                           page++;
                       } else if (contacts.length >= 10) {
                           page++;
                       } else {
                           hasMore = false;
                       }

                       consecutiveErrors = 0;
                       await new Promise(r => setTimeout(r, 400));
                   } catch (e: any) { 
                       console.error(`[Migration] Contacts page ${page} error:`, e.response?.status || e.message);
                       consecutiveErrors++;
                       if (e.response?.status === 404) hasMore = false;
                       else await new Promise(r => setTimeout(r, 2000));
                   }
                }
                console.log(`[Migration] Finished contact migration. Total: ${total}`);
                return total;
            };

            const migrateTickets = async () => {
                migrationProgress.status = 'syncing_tickets';
                let page = 1, hasMore = true, total = 0, consecutiveErrors = 0;
                console.log("[Migration] Starting ticket migration...");
                while(hasMore && consecutiveErrors < 10 && page <= 20000) {
                   try {
                       const resp = await axios.get(`https://${subdomain}.repairshopr.com/api/v1/tickets`, {
                          params: { page },
                          headers: { 'Authorization': `Bearer ${apiKey}` }
                       });
                       const tickets = resp.data.tickets || [];
                       const meta = resp.data.meta || {};
                       console.log(`[Migration] Tickets page ${page}/${meta.total_pages || '?'} - Got ${tickets.length} items. Total: ${total + tickets.length}`);

                       if (tickets.length === 0) {
                           hasMore = false;
                           break;
                       }

                       const batch = writeBatch(db);
                       for (const t of tickets) {
                          const ticketRef = doc(db, 'crm_tickets', String(t.id));
                          batch.set(ticketRef, { ...t, id: String(t.id), customer_id: String(t.customer_id), uid: 'system_migration' }, { merge: true });
                          if (t.customer_id) {
                              const customerRef = doc(db, 'crm_customers', String(t.customer_id));
                              batch.set(customerRef, {
                                  tickets: arrayUnion({ id: t.id, number: t.number, subject: t.subject || '', status: t.status || '' })
                              }, { merge: true });
                          }
                       }
                       await batch.commit();

                       total += tickets.length;
                       migrationProgress.counts.tickets = total;

                       if (meta.total_pages && page < meta.total_pages) {
                           page++;
                       } else if (tickets.length >= 10) {
                           page++;
                       } else {
                           hasMore = false;
                       }

                       consecutiveErrors = 0;
                       await new Promise(r => setTimeout(r, 400));
                   } catch (e: any) { 
                       console.error(`[Migration] Tickets page ${page} error:`, e.response?.status || e.message);
                       consecutiveErrors++;
                       if (e.response?.status === 404) hasMore = false;
                       else await new Promise(r => setTimeout(r, 2000));
                   }
                }
                console.log(`[Migration] Finished ticket migration. Total: ${total}`);
                return total;
            };

            const migrateMessages = async () => {
                migrationProgress.status = 'syncing_messages';
                const endpoints = ['ticket_comments']; 
                console.log(`[Migration] Starting focused message migration: ${endpoints.join(', ')}`);

                for (const ep of endpoints) {
                    let page = 1, hasMore = true, totalMatch = 0, consecutiveErrors = 0;

                    if (ep === 'ticket_comments') {
                        try {
                            const initialResp = await axios.get(`https://${subdomain}.repairshopr.com/api/v1/${ep}`, {
                                params: { page: 1, limit: 1 },
                                headers: { 'Authorization': `Bearer ${apiKey}` }
                            });
                            const totalPages = initialResp.data.meta?.total_pages || 1;
                            // Start from the last page and work backwards for 100 pages
                            page = Math.max(1, totalPages - 100);
                            console.log(`[Migration] ticket_comments has ${totalPages} pages. Starting from page ${page}`);
                        } catch (e) {
                            console.error("[Migration] Error getting total pages", e);
                        }
                    }

                    while(hasMore && consecutiveErrors < 3) {
                        try {
                            const resp = await axios.get(`https://${subdomain}.repairshopr.com/api/v1/${ep}`, {
                                params: { page },
                                headers: { 'Authorization': `Bearer ${apiKey}` }
                            });
                            const items = resp.data.comments || [];
                            if (!items || items.length === 0) {
                                hasMore = false;
                                break;
                            }
                            console.log(`[Migration] Processing ${items.length} comments from page ${page}`);
                            for (const s of items) {
                                const bodyLower = (s.body || '').toLowerCase();
                                const isSms = bodyLower.includes('sms') || bodyLower.includes('text message');

                                if (!isSms) continue;

                                totalMatch++;
                                const msgId = `rs_${ep}_${s.id}`;
                                const type = bodyLower.includes('sent') ? 'outbound' : 'inbound';
                                let phone = '';
                                let customerId = s.customer_id ? String(s.customer_id) : null;
                                const text = s.body || '';

                                if (!customerId && s.ticket_id) {
                                    try {
                                        const tSnap = await getDoc(doc(db, 'crm_tickets', String(s.ticket_id)));
                                        if (tSnap.exists()) {
                                            customerId = String(tSnap.data().customer_id);
                                        }
                                    } catch (e) {}
                                }

                                if (customerId) {
                                    try {
                                        const cSnap = await getDoc(doc(db, 'crm_customers', customerId));
                                        if (cSnap.exists()) {
                                            phone = cSnap.data().mobile || cSnap.data().phone || '';
                                        }
                                    } catch (e) {}
                                }

                                await setDoc(doc(db, 'messages', msgId), {
                                    from: type === 'inbound' ? (phone || 'external') : 'system',
                                    to: type === 'outbound' ? (phone || 'external') : 'system',
                                    text,
                                    timestamp: s.created_at ? new Date(s.created_at) : serverTimestamp(),
                                    status: 'delivered', type, customerId, uid: 'system_migration',
                                    repairshopr_id: s.id, rs_source: ep
                                }, { merge: true });
                                // Skipping updateConversationMetadata during bulk migration to avoid RESOURCE_EXHAUSTED
                                // if (customerId && phone) await updateConversationMetadata(customerId, phone, null, null, type as any, text);
                            }
                            page++;
                            if (resp.data.meta?.total_pages && page > resp.data.meta.total_pages) hasMore = false;
                            consecutiveErrors = 0;
                            await new Promise(r => setTimeout(r, 200));
                        } catch (e: any) { 
                            consecutiveErrors++;
                            if (e.response?.status === 404) hasMore = false;
                            else await new Promise(r => setTimeout(r, 1000));
                        }
                    }
                    migrationProgress.counts.sms = totalMatch;
                }
            };

            await migrateCustomers();
            await migrateContacts();
            await migrateTickets();
            await migrateMessages();

            migrationProgress.status = 'completed';
            console.log("[Migration] Detailed migration completed successfully.");
        } catch (err: any) {
            console.error("[Migration] Fatal Error:", err.message);
            migrationProgress.status = 'error';
            migrationProgress.error = err.message;
        }
    })();

  });

  app.post('/api/webhooks/repairshopr/new-ticket', async (req, res) => {
    try {
      const payload = req.body;
      console.log('[Webhooks] RepairShopr New Ticket received');

      await (async () => {
        try {
          if (payload && payload.ticket) {
            const ticket = payload.ticket;
            const number = ticket.number || ticket.id;

            const customer = ticket.customer || payload.customer;

            // Sync to RepairSync DB
            try {
              if (db) {
                if (customer && customer.id) {
                   const finalCustId = String(customer.id);
                   const custDataToSave = {
                     ...customer,
                     id: finalCustId,
                     created_at: customer.created_at || new Date().toISOString(),
                     updated_at: customer.updated_at || new Date().toISOString(),
                     firstname: customer.firstname || customer.first_name || '',
                     lastname: customer.lastname || customer.last_name || '',
                     uid: 'system_webhook'
                   };
                   await setDoc(doc(db, 'crm_customers', finalCustId), custDataToSave, { merge: true });
                }
                const tickId = String(ticket.id);
                const tickData = {
                  ...ticket,
                  id: tickId,
                  customer_id: String(ticket.customer_id),
                  uid: 'system_webhook'
                };
                await setDoc(doc(db, 'crm_tickets', tickId), tickData, { merge: true });

                if (ticket.customer_id) {
                   await setDoc(doc(db, 'crm_customers', String(ticket.customer_id)), {
                       tickets: arrayUnion({ id: ticket.id, number: ticket.number, subject: ticket.subject || '', status: ticket.status || '' })
                   }, { merge: true });
                }

                console.log(`[Webhooks] Synced ticket #${number} to RepairSync DB.`);
              }
            } catch (syncErr) {
              console.error('[Webhooks] Failed to sync ticket/customer to Firestore:', syncErr);
            }

            const firstName = customer ? (customer.firstname || customer.first_name || 'Customer').trim() : 'Customer';
            const phone = customer ? (customer.mobile || customer.phone) : null;

            if (phone) {
              let messageTemplate = "Hi {firstName}, your repair has been successfully booked under job #{ticketNumber}. For updates, simply reply to this message and our team will assist you shortly.\nKind regards Phone Medic Team";
              try {
                const settingsDoc = await getDoc(doc(db, 'settings', 'webhook_templates'));
                if (settingsDoc.exists() && settingsDoc.data().newTicketTemplate) {
                  messageTemplate = settingsDoc.data().newTicketTemplate;
                }
              } catch (e) {
                console.error('[Webhooks] Failed to fetch template from Firestore', e);
              }

              const message = messageTemplate
                .replace(/{firstName}/g, firstName)
                .replace(/{ticketNumber}/g, number);

              try {
                // Deduplicate webhook sending a duplicate mobilemessage via webhook retry
                const idempotencyKey = `new_ticket_sms_${number}`;
                const idempotencyRef = doc(db, 'webhook_idempotency', idempotencyKey);

                try {
                  await runTransaction(db, async (txn) => {
                    const snap = await txn.get(idempotencyRef);
                    if (snap.exists()) {
                      throw new Error('ALREADY_PROCESSED');
                    }
                    txn.set(idempotencyRef, { processedAt: serverTimestamp(), type: 'new_ticket_sms' });
                  });
                } catch (err: any) {
                  if (err.message === 'ALREADY_PROCESSED') {
                    console.log(`[Webhooks] Prevented duplicate new ticket SMS to ${phone} for ticket #${number}`);
                    return; // Skip sending SMS
                  }
                  throw err;
                }

                await axios.post(`http://127.0.0.1:${PORT}/api/mobilemessage/send`, {
                  to: phone,
                  message: message,
                  ticket_id: ticket.id || number
                });
                console.log(`[Webhooks] Sent new ticket SMS to ${phone} for ticket #${number}`);
              } catch (smsError: any) {
                console.error(`[Webhooks] Failed to send new ticket SMS:`, smsError.message);
              }
            } else {
              console.log(`[Webhooks] No phone number found for ticket #${number}, skipping SMS.`);
            }
          }
        } catch (innerErr) {
          console.error('[Webhooks] RepairShopr New Ticket Async Error:', innerErr);
        }
      })();

      if (!res.headersSent) res.status(200).send('OK');
    } catch (error: any) {
      console.error('[Webhooks] RepairShopr New Ticket Error:', error);
      if (!res.headersSent) res.status(200).send('OK');
    }
  });

