// --- Mobile Message Webhooks ---
  app.all('/api/webhooks/mobilemessage', async (req, res) => {
    try {
      const payload = Object.keys(req.body).length > 0 ? req.body : req.query;
      console.log('[Webhooks] MobileMessage payload received:', JSON.stringify({ body: req.body, query: req.query }).substring(0, 500));

      // Process and then acknowledge
      await (async () => {
        try {
          let sender, text, toField, attachmentUrl;
          if (payload.messages && Array.isArray(payload.messages) && payload.messages.length > 0) {
            const msg = payload.messages[0];
            sender = msg.from || msg.sender || msg.source;
            text = msg.message || msg.text || msg.content || '';
            toField = msg.to || msg.destination || '';
            attachmentUrl = msg.media_url || msg.image_url || msg.media || (msg.attachments && msg.attachments[0]?.url) || null;
          } else {
            sender = payload.sender || payload.from || payload.From || payload.source || payload.Source;
            text = payload.message || payload.text || payload.Message || payload.content || payload.Content || '';
            toField = payload.to || payload.destination || '';
            attachmentUrl = payload.media_url || payload.image_url || payload.media || (payload.attachments && payload.attachments[0]?.url) || null;
          }

          if (!sender || (!text && !attachmentUrl)) {
            console.warn('[Webhooks] MobileMessage: Missing sender or text/attachment', JSON.stringify(payload));
            return;
          }

          const normalizedFrom = normalizePhone(sender);
          const localFormatFrom = sender.startsWith('61') ? '0' + sender.substring(2) : (sender.startsWith('0') ? sender : sender);

          const subdomain = process.env.REPAIRSHOPR_SUBDOMAIN;
          const apiKey = process.env.REPAIRSHOPR_API_KEY;

          let customerId = null;
          let customerName = null;
          let ticketIdLog = null;
          let ticketNumberLog = null;

          // Search CRM
          try {
            const crmCustSnap = await getDocs(collection(db, 'crm_customers'));
            crmCustSnap.forEach(d => {
              const c = d.data();
              if (normalizePhone(c.phone || '') === normalizedFrom || normalizePhone(c.mobile || '') === normalizedFrom) {
                customerId = d.id;
                customerName = c.fullname || `${c.firstname || ''} ${c.lastname || ''}`.trim();
              }
            });

            if (customerId) {
              const q = query(collection(db, 'crm_tickets'), where('customer_id', '==', customerId));
              const crmTickSnap = await getDocs(q);
              const crmTickets = crmTickSnap.docs.map(d => ({ id: d.id, ...d.data() })).sort((a: any, b: any) => {
                const aT = a.created_at?.seconds || 0;
                const bT = b.created_at?.seconds || 0;
                return bT - aT;
              });
              if (crmTickets.length > 0) {
                const active: any = crmTickets.find((t: any) => t.status !== 'Resolved' && t.status !== 'Completed') || crmTickets[0];
                ticketIdLog = active.id;
                ticketNumberLog = active.number;
              }
            }
          } catch (e) {}

          // Fallback RepairShopr
          if (!customerId && subdomain && apiKey) {
            try {
              const rsCustRes = await axios.get(`https://${subdomain}.repairshopr.com/api/v1/customers`, {
                params: { query: localFormatFrom },
                headers: { 'Authorization': `Bearer ${apiKey}` }
              });
              const customers = rsCustRes.data.customers || [];
              if (customers.length > 0) {
                const customer = customers[0];
                customerId = String(customer.id);
                customerName = customer.fullname || `${customer.first_name || ''} ${customer.last_name || ''}`.trim();
                const rsTicksRes = await axios.get(`https://${subdomain}.repairshopr.com/api/v1/tickets`, {
                  params: { customer_id: customerId },
                  headers: { 'Authorization': `Bearer ${apiKey}` }
                });
                const tickets = rsTicksRes.data.tickets || [];
                if (tickets.length > 0) {
                  const active = tickets.find((t: any) => t.status !== 'Resolved') || tickets[0];
                  ticketIdLog = String(active.id);
                  ticketNumberLog = active.number;
                }
              }
            } catch (e) {}
          }

          // Deduplicate inbound messages using Idempotency Collection
          let originalMessageId = null;
          if (payload.messages && Array.isArray(payload.messages) && payload.messages.length > 0) {
            const msg = payload.messages[0];
            originalMessageId = msg.message_id || msg.id || msg.messageId;
          } else {
            originalMessageId = payload.message_id || payload.id || payload.messageId || payload.MessageId;
          }

          if (originalMessageId) {
            const idempotencyRef = doc(db, 'webhook_idempotency', String(originalMessageId));
            try {
              await runTransaction(db, async (txn) => {
                const snap = await txn.get(idempotencyRef);
                if (snap.exists()) {
                  throw new Error('ALREADY_PROCESSED');
                }
                txn.set(idempotencyRef, { processedAt: serverTimestamp(), type: 'sms_inbound' });
              });
            } catch (err: any) {
              if (err.message === 'ALREADY_PROCESSED') {
                console.log(`[Webhooks] MobileMessage: Ignored duplicate inbound SMS based on idempotency (msgId: ${originalMessageId})`);
                return;
              }
              throw err;
            }
          } else {
            const oneMinuteAgo = new Date(Date.now() - 60000);
            const recentMsgsQuery = query(collection(db, 'messages'), where('from', '==', localFormatFrom));
            const recentSnap = await getDocs(recentMsgsQuery);
            const isDuplicate = recentSnap.docs.some(doc => {
               const data = doc.data();
               if (data.type !== 'inbound' || data.text !== text) return false;
               const t = data.timestamp;
               if (!t) return false;
               return t.toDate() > oneMinuteAgo;
            });

            if (isDuplicate) {
