app.post('/api/mobilemessage/sync', async (req, res) => {
    try {
      const username = process.env.MOBILE_MESSAGE_USERNAME;
      const password = process.env.MOBILE_MESSAGE_PASSWORD;
      if (!username || !password) return res.status(401).json({ error: 'Config missing' });

      const authHeader = 'Basic ' + Buffer.from(`${username}:${password}`).toString('base64');

      // Date threshold for 30 days ago
      const thirtyDaysAgo = new Date();
      thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

      let offset = 0;
      const limitCount = 100;
      let hasMore = true;
      let syncedCount = 0;
      let processedIds = new Set();

      // Fetch CRM customers ONCE
      const crmMap = new Map(); // key is normalized phone, value is { id, fullname }
      const crmCustSnap = await getDocs(collection(db, 'crm_customers'));
      crmCustSnap.forEach(d => {
        const c = d.data();
        const fullname = c.fullname || `${c.firstname || ''} ${c.lastname || ''}`.trim();
        const pPhone = normalizePhone(c.phone || '');
        const pMobile = normalizePhone(c.mobile || '');
        if (pPhone) crmMap.set(pPhone, { id: d.id, name: fullname });
        if (pMobile) crmMap.set(pMobile, { id: d.id, name: fullname });
      });

      // 1. Sync Inbound SMS
      while (hasMore) {
        const response = await axios.get('https://api.mobilemessage.com.au/v1/inbound', {
          headers: { 'Authorization': authHeader },
          params: { offset, limit: limitCount }
        });

        const messages = response.data.results || [];
        if (messages.length === 0) {
          hasMore = false;
          break;
        }

        let shouldStop = false;

        // Process messages in parallel to avoid slow sequential await
        await Promise.all(messages.map(async (msg: any) => {
          if (processedIds.has(msg.message_id)) return;
          processedIds.add(msg.message_id);

          const from = msg.from;
          const text = msg.message || '';
          const attachmentUrl = msg.media_url || msg.image_url || msg.media || (msg.attachments && msg.attachments[0]?.url) || null;
          const timestampStr = msg.received_at;

          if (!from || (!text && !attachmentUrl) || !timestampStr) return;

          // Parse timestamp (usually 'YYYY-MM-DD HH:mm:ss' in UTC or local)
          const timestamp = new Date(timestampStr.replace(' ', 'T') + 'Z');

          if (timestamp < thirtyDaysAgo) {
            shouldStop = true;
            return;
          }

          const normalizedFrom = normalizePhone(from);
          const localFormatFrom = from.startsWith('61') ? '0' + from.substring(2) : (from.startsWith('0') ? from : from);

          let customerId = null;
          let customerName = null;
          let ticketNumberLog = null;

          // Search CRM
          const matchedCrm = crmMap.get(normalizedFrom);
          if (matchedCrm) {
            customerId = matchedCrm.id;
            customerName = matchedCrm.name;
          }

          // Basic duplicate check using the explicit firestore limit check
          const possibleFroms = Array.from(new Set([localFormatFrom, normalizedFrom, '+' + normalizedFrom].filter(Boolean)));
          let isDuplicate = false;
          if (possibleFroms.length > 0) {
            const existingQ = query(collection(db, 'messages'), 
                               where('from', 'in', possibleFroms),
                               where('type', '==', 'inbound'));
            const existingDocs = await getDocs(existingQ);

            existingDocs.forEach(doc => {
            const data = doc.data();
            const dbText = (data.text || '').replace(/\s+/g, '').toLowerCase();
            const msgText = (text || '').replace(/\s+/g, '').toLowerCase();
            if (dbText === msgText || (msgText.length > 5 && dbText.includes(msgText.substring(0, 20))) || (dbText.length > 5 && msgText.includes(dbText.substring(0, 20)))) {
               const dbTime = data.timestamp?.toDate ? data.timestamp.toDate() : new Date((data.timestamp?.seconds || 0) * 1000);
               if (Math.abs(dbTime.getTime() - timestamp.getTime()) < 24 * 60 * 60 * 1000) {
                 isDuplicate = true;
               }
            } else if (!text && !dbText && !!data.attachmentUrl === !!attachmentUrl) {
               const dbTime = data.timestamp?.toDate ? data.timestamp.toDate() : new Date((data.timestamp?.seconds || 0) * 1000);
               if (Math.abs(dbTime.getTime() - timestamp.getTime()) < 24 * 60 * 60 * 1000) {
                 isDuplicate = true;
               }
            }
          });
          }

          if (!isDuplicate) {
            await addDoc(collection(db, 'messages'), {
              from: localFormatFrom,
              to: 'system',
              text: text,
              attachmentUrl: attachmentUrl || null,
              attachmentType: attachmentUrl ? 'image/jpeg' : null,
              timestamp: timestamp,
              status: 'received',
              type: 'inbound',
              customerId,
              customerName,
              ticketNumber: ticketNumberLog,
              uid: 'api-sync',
              isUnread: true
            });
            let previewText = text;
            if (!previewText && attachmentUrl) previewText = "📎 Attachment";
            await updateConversationMetadata(customerId, localFormatFrom, customerName, ticketNumberLog, 'inbound', previewText);
            syncedCount++;
          }
        }));

        if (shouldStop) {
          hasMore = false;
          break;
        }

        if (hasMore) {
          offset += limitCount;
          // Stop if we've processed too many pages just in case
          if (offset > 5000) {
            hasMore = false;
          }
        }
      }

      // 2. Sync Outbound SMS
      let outboundOffset = 0;
      let hasMoreOutbound = true;
      let processedOutboundIds = new Set();

      while (hasMoreOutbound) {
        const response = await axios.get('https://api.mobilemessage.com.au/v1/messages', {
          headers: { 'Authorization': authHeader },
          params: { offset: outboundOffset, limit: limitCount }
        });

        const messages = response.data.results || [];
        if (messages.length === 0) {
          hasMoreOutbound = false;
          break;
        }

        let shouldStop = false;

        await Promise.all(messages.map(async (msg: any) => {
          if (processedOutboundIds.has(msg.message_id)) return;
          processedOutboundIds.add(msg.message_id);

          const to = msg.recipient_number;
          const text = msg.message_content;
          const timestampStr = msg.requested_at || msg.scheduled_for;

          if (!to || !text || !timestampStr) return;

          const timestamp = new Date(timestampStr.replace(' ', 'T') + 'Z');

          if (timestamp < thirtyDaysAgo) {
            shouldStop = true;
            return;
          }

          const normalizedTo = normalizePhone(to);
          const localFormatTo = to.startsWith('61') ? '0' + to.substring(2) : (to.startsWith('0') ? to : to);

          let customerId = null;
          let customerName = null;
          let ticketNumberLog = null;

          const matchedCrm = crmMap.get(normalizedTo);
          if (matchedCrm) {
            customerId = matchedCrm.id;
            customerName = matchedCrm.name;
          }

          const possibleTos = Array.from(new Set([localFormatTo, normalizedTo, '+' + normalizedTo].filter(Boolean)));

          let isDuplicate = false;
          if (possibleTos.length > 0) {
            const existingQ = query(collection(db, 'messages'), 
                               where('to', 'in', possibleTos),
                               where('type', '==', 'outbound'));
            const existingDocs = await getDocs(existingQ);

            existingDocs.forEach(doc => {
            const data = doc.data();
            const dbText = (data.text || '').replace(/\s+/g, '').toLowerCase();
            const msgText = (text || '').replace(/\s+/g, '').toLowerCase();
            if (dbText === msgText || dbText.includes(msgText.substring(0, 20)) || msgText.includes(dbText.substring(0, 20))) {
              // Also maybe check timestamp within 24 hours just to be safe
              const dbTime = data.timestamp?.toDate ? data.timestamp.toDate() : new Date((data.timestamp?.seconds || 0) * 1000);
              if (Math.abs(dbTime.getTime() - timestamp.getTime()) < 24 * 60 * 60 * 1000) {
                 isDuplicate = true;
              }
            }
          });
          }

          if (!isDuplicate) {
            await addDoc(collection(db, 'messages'), {
              from: 'system',
              to: localFormatTo,
              text: text,
              timestamp: timestamp,
              status: msg.status === 'delivered' ? 'delivered' : 'sent',
              type: 'outbound',
              customerId,
              customerName,
              ticketNumber: ticketNumberLog,
              uid: 'api-sync',
              isUnread: false
            });
            await updateConversationMetadata(customerId, localFormatTo, customerName, ticketNumberLog, 'outbound', text);
            syncedCount++;
          }
        }));

        if (shouldStop) {
          hasMoreOutbound = false;
          break;
        }

        if (hasMoreOutbound) {
          outboundOffset += limitCount;
          if (outboundOffset > 5000) {
            hasMoreOutbound = false;
          }
        }
      }

      res.json({ success: true, syncedCount, lookedAt: offset + processedIds.size + outboundOffset + processedOutboundIds.size });
    } catch (error: any) {
      console.error('[Sync] MobileMessage Sync Error:', error.response?.data || error.message);
      res.status(500).json({ error: error.message, details: error.response?.data });
    }
  });

