app.get('/api/mobilemessage/balance', async (req, res) => {
    try {
      const username = process.env.MOBILE_MESSAGE_USERNAME;
      const password = process.env.MOBILE_MESSAGE_PASSWORD;

      if (!username || !password) {
         return res.json({ credit_balance: null });
      }

      // Return cached balance if fetched within the last 5 minutes (300000 ms)
      // to reduce hitting the MobileMessage API too often
      if (cachedBalance !== null && Date.now() - lastBalanceFetch < 300000) {
         return res.json({ credit_balance: cachedBalance });
      }

      const authHeader = 'Basic ' + Buffer.from(`${username}:${password}`).toString('base64');

      const balanceEndpoints = [
        { url: 'https://api.mobilemessage.com.au/v1/account', headers: { 'Authorization': authHeader } },
        { url: 'https://api.mobilemessage.com.au/simple/get-balance.php', params: { api_username: username, api_password: password } }
      ];

      let lastBalanceErr = null;
      let rateLimited = false;
      for (const endpoint of balanceEndpoints) {
        try {
          console.log(`[SMS] Trying balance endpoint: ${endpoint.url}`);
          const response = await axios.get(endpoint.url, {
             headers: endpoint.headers,
             params: endpoint.params
          });

      cachedBalance = response.data.credit_balance || response.data.balance || (response.data.data ? response.data.data.balance : 0);
          lastBalanceFetch = Date.now();
          return res.json({ 
            credit_balance: cachedBalance,
            description: "Remaining SMS credits in your account. Each credit allows sending 1 SMS of up to 160 characters."
          });
        } catch (inner: any) {
          const errData = inner.response?.data || inner.message;
          lastBalanceErr = errData;
          if (inner.response?.status === 429 || JSON.stringify(errData).includes("Rate exceeded") || String(errData).includes("Rate exceeded")) {
             rateLimited = true;
             break;
          }
          continue;
        }
      }

      if (rateLimited) {
         // Cache for 5 minutes even if rate limited to prevent continuous fetching
         lastBalanceFetch = Date.now();
         if (cachedBalance === null) cachedBalance = "Rate Limited"; // store as string temporary or just keep it null 
         return res.json({ credit_balance: cachedBalance === "Rate Limited" ? null : cachedBalance });
      }

      throw new Error(typeof lastBalanceErr === 'string' ? lastBalanceErr : 'Balance fetch failed');
    } catch (error: any) {
      if (error.response?.status === 429 || error.message?.includes('Rate exceeded')) {
         // Return cached if we hit a rate limit just in case
         lastBalanceFetch = Date.now();
         if (cachedBalance !== null) return res.json({ credit_balance: cachedBalance === "Rate Limited" ? null : cachedBalance });
         return res.status(429).json({ error: 'Rate exceeded. Please wait.' });
      }
      res.status(error.response?.status || 500).json(error.response?.data || { error: error.message });
    }
  });

