              timestamp: serverTimestamp(),
              status: 'delivered', 
              type: direction,
              isCall: true,
              isWebhook: true,
              uid: 'webhook',
              customerId,
              customerName,
              ticketId: ticketIdLog,
              ticketNumber: ticketNumberLog
            });
            fs.appendFileSync('maxotel.log', `Saved Call for ${customerName} - Ticket: ${ticketNumberLog}\n`);
          }

